import React, { useState, useEffect, useRef, useMemo } from 'react';

const ITEMS = [
    { id: 1, name: 'JavaScript Framework Guide', category: 'frontend' },
    { id: 2, name: 'Python Data Science Handbook', category: 'data' },
    { id: 3, name: 'React Performance Optimization', category: 'frontend' },
    { id: 4, name: 'Node.js Backend Architecture', category: 'backend' },
    { id: 5, name: 'SQL Query Optimization Techniques', category: 'database' },
    { id: 6, name: 'TypeScript Advanced Patterns', category: 'frontend' },
    { id: 7, name: 'Docker Container Security', category: 'devops' },
    { id: 8, name: 'GraphQL API Design', category: 'backend' },
    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

/**
 * Custom debounce hook (no lodash).
 * Returns [debouncedValue, isPending].
 * 300ms delay. Cleans up timeout on unmount and on new changes.
 */
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);
    const timeoutRef = useRef(null);
    const isFirstRenderRef = useRef(true);

    useEffect(() => {
        // Avoid showing "Searching..." and unnecessary work on initial mount
        if (isFirstRenderRef.current) {
            isFirstRenderRef.current = false;
            setDebouncedValue(value);
            return;
        }

        setIsPending(true);

        if (timeoutRef.current !== null) {
            clearTimeout(timeoutRef.current);
        }

        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
            timeoutRef.current = null;
        }, delay);

        // Cleanup: prevents memory leaks on unmount or when value/delay changes
        return () => {
            if (timeoutRef.current !== null) {
                clearTimeout(timeoutRef.current);
                timeoutRef.current = null;
            }
        };
    }, [value, delay]);

    return [debouncedValue, isPending];
}

function ResourceList() {
    const [searchTerm, setSearchTerm] = useState('');
    const [debouncedSearchTerm, isSearching] = useDebouncedValue(searchTerm, 300);

    // Trim so whitespace-only input is treated as "no query"
    const query = debouncedSearchTerm.trim();
    const lowerQuery = query.toLowerCase();

    // Case-insensitive substring filter on name (memoized)
    const filteredItems = useMemo(() => {
        if (!lowerQuery) {
            return ITEMS;
        }
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(lowerQuery)
        );
    }, [lowerQuery]);

    /**
     * Returns text with matching portion wrapped in <mark>.
     * Safely escapes regex metacharacters so queries like "C++", "node.js", ".*", etc.
     * never cause errors and always perform literal substring matching.
     */
    const highlightMatch = (text, searchQuery) => {
        if (!searchQuery) {
            return text;
        }

        const escaped = searchQuery.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp(`(${escaped})`, 'gi');
        const parts = text.split(regex);

        return parts.map((part, index) => {
            if (part.toLowerCase() === searchQuery.toLowerCase()) {
                return <mark key={index}>{part}</mark>;
            }
            return part;
        });
    };

    return (
        <div>
            <h2>Resources</h2>

            <div>
                <input
                    type="text"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder="Search resources..."
                    aria-label="Search resources"
                />
                {isSearching && <span> Searching...</span>}
            </div>

            {/* 
              While isSearching is true we continue showing the previous results (or all items).
              After the 300ms debounce resolves:
                - Non-empty query + 0 matches → "No results found"
                - Otherwise → filtered (or full) list with highlighting
              Whitespace-only input is normalized to empty (shows everything).
            */}
            {!isSearching && query && filteredItems.length === 0 ? (
                <p>No results found.</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, query)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
```

### How the requirements are addressed:
- **Search input** at the top with live `value` + `onChange`.
- **Custom 300ms debounce** via `useDebouncedValue` hook (implemented with `useRef` + `setTimeout`; no external libs).
- **Filtering**: case-insensitive `includes` on `name`.
- **"Searching..." indicator**: shown inline next to the input only while the debounce timer is active.
- **Empty input** (including whitespace-only after trim) shows the full list.
- **Highlighting**: matching text wrapped in `<mark>` (original casing preserved).
- **"No results found"**: shown only after debounce completes for a non-empty query with zero matches.
- **Cleanup**: `useEffect` return clears the timeout on unmount or before scheduling a new one.
- **Edge cases**: `query.trim()` treats whitespace-only as empty; `replace(/[.*+?^${}()|[\]\\]/g, '\\$&')` escapes special characters so regex never throws and matching stays literal.

The previous results list remains visible during the debounce window (good UX), then either updates or is replaced by the no-results message. A copy of this file was also written to the workspace at `benchmark/ResourceList.jsx` for reference.
